import 'dart:io';

import 'package:sugar/sugar.dart';

import '../../args/command.dart';
import '../../args/utils.dart';
import '../../configuration.dart';
import 'command.dart';

final separator = RegExp('_|-');

const themeHeader = '''
import 'package:forui/forui.dart';
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';

part 'colors.dart';
part 'typography.dart';
part 'style.dart';

/// Generated by Forui CLI.
///
/// Modify the generated function bodies to create your own custom style.
/// Then, call the modified function and pass it to [FTheme].
///
/// You can also generate styles to be used in the generated [FThemeData] using:
/// ```shell
/// dart forui style create [styles]
/// ```
///
/// See:
/// * https://forui.dev/docs/guides/customizing-themes for customizing themes.
/// * https://forui.dev/docs/guides/customizing-widget-styles for customizing individual widget styles.''';

String _colorsHeader(String themeFileName) =>
    '''
part of '$themeFileName';

/// Generated by Forui CLI.
///
/// Color tokens and theme extensions for the generated theme.''';

String _typographyHeader(String themeFileName) =>
    '''
part of '$themeFileName';

/// Generated by Forui CLI.
///
/// Typography tokens and theme extensions for the generated theme.''';

String _styleHeader(String themeFileName) =>
    '''
part of '$themeFileName';

// ignore_for_file: avoid_redundant_argument_values

/// Generated by Forui CLI.
///
/// Style tokens and theme extensions for the generated theme.''';

class ThemeCreateCommand extends ForuiCommand {
  @override
  final name = 'create';

  @override
  final aliases = ['c'];

  @override
  final description = 'Creates a Forui theme file.\n\nRun "dart run forui theme ls" to see all themes.';

  @override
  final arguments = '[theme]';

  final Configuration configuration;

  ThemeCreateCommand(this.configuration) {
    argParser
      ..addFlag('force', abbr: 'f', help: 'Overwrite existing files if they exist.', negatable: false)
      ..addOption(
        'output',
        abbr: 'o',
        help: 'The output directory or file, relative to the project directory.',
        defaultsTo: configuration.theme,
      );
  }

  @override
  void run() {
    final input = !globalResults!.flag('no-input');
    final force = argResults!.flag('force');
    final output = argResults!['output'] as String;
    final arguments = argResults!.rest;

    if (arguments.length != 1) {
      printUsage();
      return;
    }

    if (!_validate(arguments.single)) {
      exit(1);
    }

    _generate(arguments.single, input: input, force: force, output: output);
  }

  bool _validate(String theme) {
    if (registry.containsKey(theme)) {
      return true;
    }

    final suggestions =
        registry.keys.map((e) => (e, e.startsWith(theme) ? 1 : distance(theme, e))).where((e) => e.$2 <= 3).toList()
          ..sort((a, b) => a.$2.compareTo(b.$2));

    stdout.writeln('Could not find a theme named "$theme".');

    if (suggestions.isNotEmpty) {
      stdout
        ..writeln()
        ..writeln('Did you mean one of these?');

      for (final (suggestion, _) in suggestions) {
        stdout.writeln('  $suggestion');
      }
    }

    stdout
      ..writeln()
      ..writeln('Run "dart run forui theme ls" to see all themes.');

    return false;
  }

  void _generate(String argument, {required bool input, required bool force, required String output}) {
    final theme = registry[argument]!;
    final fileName = theme.name.toSnakeCase();
    final themePath =
        '${configuration.root.path}${Platform.pathSeparator}${output.endsWith('.dart') ? output : '$output${Platform.pathSeparator}$fileName.dart'}';
    final themeDir = File(themePath).parent.path;
    final themeFileName = themePath.split(Platform.pathSeparator).last;
    final colorsPath = '$themeDir${Platform.pathSeparator}colors.dart';
    final typographyPath = '$themeDir${Platform.pathSeparator}typography.dart';
    final stylePath = '$themeDir${Platform.pathSeparator}style.dart';

    if (!force) {
      for (final path in [themePath, colorsPath, typographyPath, stylePath]) {
        if (File(path).existsSync()) {
          _prompt(path, input: input);
        }
      }
    }

    stdout
      ..writeln('${emoji ? '⏳' : '[Waiting]'} Creating themes...')
      ..writeln();

    final themeBuffer = StringBuffer('$themeHeader\n')
      ..writeln(theme.source)
      ..writeln();
    final colorsBuffer = StringBuffer('${_colorsHeader(themeFileName)}\n')
      ..writeln(theme.colors)
      ..writeln();
    final typographyBuffer = StringBuffer('${_typographyHeader(themeFileName)}\n')
      ..writeln(theme.typography)
      ..writeln();
    final styleBuffer = StringBuffer('${_styleHeader(themeFileName)}\n')
      ..writeln(theme.style)
      ..writeln();

    File(themePath)
      ..createSync(recursive: true)
      ..writeAsStringSync(formatter.format(themeBuffer.toString()));
    File(colorsPath)
      ..createSync(recursive: true)
      ..writeAsStringSync(formatter.format(colorsBuffer.toString()));
    File(typographyPath)
      ..createSync(recursive: true)
      ..writeAsStringSync(formatter.format(typographyBuffer.toString()));
    File(stylePath)
      ..createSync(recursive: true)
      ..writeAsStringSync(formatter.format(styleBuffer.toString()));

    stdout
      ..writeln('${emoji ? '✅' : '[Done]'} ${Uri.file(themePath)}')
      ..writeln('${emoji ? '✅' : '[Done]'} ${Uri.file(colorsPath)}')
      ..writeln('${emoji ? '✅' : '[Done]'} ${Uri.file(typographyPath)}')
      ..writeln('${emoji ? '✅' : '[Done]'} ${Uri.file(stylePath)}')
      ..writeln()
      ..writeln('See https://forui.dev/docs/guides/customizing-themes for how to use the generated theme.');
  }

  void _prompt(String existing, {required bool input}) {
    if (!input) {
      stdout.writeln('Theme file already exists. Skipping... ');
      exit(0);
    }

    while (true) {
      stdout.write('${emoji ? '⚠️' : '[Warning]'} ${Uri.file(existing)} already exists. Overwrite it? [Y/n] ');

      switch (stdin.readLineSync()) {
        case 'y' || 'Y' || '':
          return;
        case 'n' || 'N':
          exit(0);
        default:
          stdout.writeln('Invalid option. Please enter enter either "y" or "n".');
      }
    }
  }
}
